1	package docprose
2	
3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"runtime"
8	
9		"gopkg.in/yaml.v3"
10	)
11	
12	const assetRootDir = "library/checks/prose-quality"
13	
14	type defaultConfig struct {
15		Mode       string     `yaml:"mode"`
16		Severity   string     `yaml:"severity"`
17		Policy     string     `yaml:"policy"`
18		Runner     string     `yaml:"runner"`
19		Vale       ValeConfig `yaml:"vale"`
20		StylePack  StylePack  `yaml:"rule_pack"`
21		Includes   []string   `yaml:"includes"`
22		Excludes   []string   `yaml:"excludes"`
23		Vocabulary Vocabulary `yaml:"vocabulary"`
24	}
25	
26	type ValeConfig struct {
27		Version    string `yaml:"version"`
28		StylesPath string `yaml:"styles_path"`
29		Style      string `yaml:"style"`
30	}
31	
32	type StylePack struct {
33		Name    string      `yaml:"name"`
34		Version string      `yaml:"version"`
35		Path    string      `yaml:"path"`
36		Rules   []StyleRule `yaml:"rules"`
37	}
38	
39	type StyleRule struct {
40		File   string `yaml:"file"`
41		RuleID string `yaml:"rule_id"`
42	}
43	
44	type rulePack struct {
45		Mode  string     `yaml:"mode"`
46		Rules []ruleSpec `yaml:"rules"`
47	}
48	
49	type ruleSpec struct {
50		ID            string   `yaml:"id"`
51		Severity      string   `yaml:"severity"`
52		Rationale     string   `yaml:"rationale"`
53		SuggestedEdit string   `yaml:"suggested_edit"`
54		ContainsAny   []string `yaml:"contains_any,omitempty"`
55		Kind          string   `yaml:"kind,omitempty"`
56	}
57	
58	type Vocabulary struct {
59		DefaultPath string   `yaml:"default_path,omitempty"`
60		ValeStyle   string   `yaml:"vale_style,omitempty"`
61		Accept      []string `yaml:"accept"`
62		Reject      []string `yaml:"reject"`
63	}
64	
65	func defaultAssetRoot() (string, error) {
66		_, file, _, ok := runtime.Caller(0)
67		if !ok {
68			return "", fmt.Errorf("locate docprose assets: runtime caller unavailable")
69		}
70		dir := filepath.Dir(file)
71		root := filepath.Clean(filepath.Join(dir, "..", "..", ".."))
72		return filepath.Join(root, assetRootDir), nil
73	}
74	
75	func loadDefaultConfig() (defaultConfig, error) {
76		root, err := defaultAssetRoot()
77		if err != nil {
78			return defaultConfig{}, err
79		}
80		data, err := os.ReadFile(filepath.Join(root, "check.yaml"))
81		if err != nil {
82			return defaultConfig{}, fmt.Errorf("read default config: %w", err)
83		}
84		var cfg defaultConfig
85		if err := yaml.Unmarshal(data, &cfg); err != nil {
86			return defaultConfig{}, fmt.Errorf("parse default config: %w", err)
87		}
88		return cfg, nil
89	}
90	
91	func loadRulePack(mode string) ([]ruleSpec, error) {
92		root, err := defaultAssetRoot()
93		if err != nil {
94			return nil, err
95		}
96		data, err := os.ReadFile(filepath.Join(root, "rules", mode+".yaml"))
97		if err != nil {
98			return nil, fmt.Errorf("read %s rules: %w", mode, err)
99		}
100		var pack rulePack
101		if err := yaml.Unmarshal(data, &pack); err != nil {
102			return nil, fmt.Errorf("parse %s rules: %w", mode, err)
103		}
104		if pack.Mode != mode {
105			return nil, fmt.Errorf("rules file mode %q does not match requested mode %q", pack.Mode, mode)
106		}
107		return pack.Rules, nil
108	}
109	
110	func loadDefaultVocabulary() (Vocabulary, error) {
111		root, err := defaultAssetRoot()
112		if err != nil {
113			return Vocabulary{}, err
114		}
115		data, err := os.ReadFile(filepath.Join(root, "vocabulary", "default.yaml"))
116		if err != nil {
117			return Vocabulary{}, fmt.Errorf("read default vocabulary: %w", err)
118		}
119		var vocab Vocabulary
120		if err := yaml.Unmarshal(data, &vocab); err != nil {
121			return Vocabulary{}, fmt.Errorf("parse default vocabulary: %w", err)
122		}
123		return vocab, nil
124	}
