1	package cmd
2	
3	import (
4		"context"
5		"fmt"
6		"os"
7		"os/exec"
8		"path/filepath"
9		"sort"
10		"strings"
11	
12		"github.com/DocumentDrivenDX/ddx/internal/config"
13		"github.com/DocumentDrivenDX/ddx/internal/docprose"
14		internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
15		"github.com/spf13/cobra"
16	)
17	
18	func (f *CommandFactory) newDocProseCommand() *cobra.Command {
19		cmd := &cobra.Command{
20			Use:   "prose [paths...]",
21			Short: "Check prose quality in Markdown documents",
22			Long: `Check prose quality in changed Markdown files or explicit paths.
23	
24	The default surface is advisory. Findings are deterministic and
25	machine-readable, with file, line, rule id, severity, rationale, and
26	suggested edit fields.`,
27			Args: cobra.ArbitraryArgs,
28			RunE: func(cmd *cobra.Command, args []string) error {
29				return f.runDocProse(cmd, args)
30			},
31		}
32		cmd.Flags().Bool("changed", false, "Check changed Markdown files in the current git repo")
33		return cmd
34	}
35	
36	func (f *CommandFactory) runDocProse(cmd *cobra.Command, args []string) error {
37		changed, _ := cmd.Flags().GetBool("changed")
38	
39		cfg, err := config.LoadWithWorkingDir(f.docRoot())
40		if err != nil {
41			return err
42		}
43	
44		settings, err := docprose.ResolveSettings(cfg)
45		if err != nil {
46			return err
47		}
48	
49		if err := maybeReportMissingRunner(cmd, settings.Runner); err != nil {
50			return err
51		}
52	
53		rootDir := f.docRoot()
54		var relPaths []string
55		if changed {
56			if len(args) > 0 {
57				return fmt.Errorf("use either --changed or explicit paths, not both")
58			}
59			relPaths, err = changedMarkdownPaths(rootDir)
60			if err != nil {
61				return err
62			}
63		} else {
64			if len(args) == 0 {
65				return fmt.Errorf("provide one or more paths or pass --changed")
66			}
67			relPaths = append([]string(nil), args...)
68		}
69	
70		checker, err := docprose.NewChecker(settings.Mode, settings.Vocabulary)
71		if err != nil {
72			return err
73		}
74	
75		var findings []docprose.Finding
76		for _, relPath := range relPaths {
77			cleanRel, absPath, ok := normalizeDocPath(rootDir, relPath)
78			if !ok {
79				continue
80			}
81			if !strings.EqualFold(filepath.Ext(cleanRel), ".md") {
82				continue
83			}
84			if !pathAllowed(cleanRel, settings.Includes, settings.Excludes) {
85				continue
86			}
87			content, readErr := os.ReadFile(absPath)
88			if readErr != nil {
89				if os.IsNotExist(readErr) {
90					continue
91				}
92				return fmt.Errorf("read %s: %w", relPath, readErr)
93			}
94			for _, finding := range checker.Findings(cleanRel, string(content)) {
95				if settings.Severity != "" {
96					finding.Severity = settings.Severity
97				}
98				findings = append(findings, finding)
99			}
100		}
101	
102		sort.Slice(findings, func(i, j int) bool {
103			if findings[i].File != findings[j].File {
104				return findings[i].File < findings[j].File
105			}
106			if findings[i].Line != findings[j].Line {
107				return findings[i].Line < findings[j].Line
108			}
109			return findings[i].RuleID < findings[j].RuleID
110		})
111	
112		out := cmd.OutOrStdout()
113		if len(findings) == 0 {
114			if changed {
115				fmt.Fprintln(out, "No changed Markdown prose findings.")
116			} else {
117				fmt.Fprintln(out, "No prose findings.")
118			}
119			return nil
120		}
121	
122		for _, finding := range findings {
123			fmt.Fprintf(out, "%s:%d [%s] %s\n", finding.File, finding.Line, finding.Severity, finding.RuleID)
124			fmt.Fprintf(out, "  rationale: %s\n", finding.Rationale)
125			fmt.Fprintf(out, "  suggested edit: %s\n", finding.SuggestedEdit)
126		}
127	
128		if isBlockingProsePolicy(settings.Policy, settings.Severity) {
129			cmd.SilenceUsage = true
130			cmd.SilenceErrors = true
131			return NewExitError(ExitCodeGeneralError, "")
132		}
133		return nil
134	}
135	
136	func maybeReportMissingRunner(cmd *cobra.Command, runner string) error {
137		runner = strings.TrimSpace(strings.ToLower(runner))
138		switch runner {
139		case "", "embedded":
140			return nil
141		case "auto", "vale":
142			if _, err := exec.LookPath("vale"); err != nil {
143				fmt.Fprintf(cmd.ErrOrStderr(), "warning: optional prose runner %q is unavailable; using embedded checker\n", "vale")
144			}
145			return nil
146		default:
147			return fmt.Errorf("unsupported prose runner %q", runner)
148		}
149	}
150	
151	func isBlockingProsePolicy(policy, severity string) bool {
152		return strings.EqualFold(policy, "blocking") || strings.EqualFold(severity, "blocking")
153	}
154	
155	func changedMarkdownPaths(rootDir string) ([]string, error) {
156		out, err := internalgit.Command(context.Background(), rootDir, "status", "--porcelain=v1", "--untracked-files=all").Output()
157		if err != nil {
158			return nil, fmt.Errorf("git status failed: %w", err)
159		}
160	
161		var paths []string
162		for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
163			if line == "" || len(line) < 3 {
164				continue
165			}
166			status := line[:2]
167			pathText := strings.TrimSpace(line[3:])
168			if pathText == "" {
169				continue
170			}
171			if strings.Contains(pathText, " -> ") {
172				parts := strings.Split(pathText, " -> ")
173				pathText = parts[len(parts)-1]
174			}
175			if strings.ContainsRune(status, 'D') {
176				continue
177			}
178			if !strings.EqualFold(filepath.Ext(pathText), ".md") {
179				continue
180			}
181			paths = append(paths, filepath.ToSlash(pathText))
182		}
183		sort.Strings(paths)
184		return paths, nil
185	}
186	
187	func normalizeDocPath(rootDir, input string) (string, string, bool) {
188		if strings.TrimSpace(input) == "" {
189			return "", "", false
190		}
191		absPath := input
192		if !filepath.IsAbs(input) {
193			absPath = filepath.Join(rootDir, input)
194		}
195		absPath = filepath.Clean(absPath)
196		relPath, err := filepath.Rel(rootDir, absPath)
197		if err != nil {
198			relPath = filepath.ToSlash(filepath.Clean(input))
199		} else {
200			relPath = filepath.ToSlash(relPath)
201		}
202		return relPath, absPath, true
203	}
204	
205	func pathAllowed(relPath string, includes, excludes []string) bool {
206		relPath = filepath.ToSlash(relPath)
207		if len(includes) > 0 && !anyGlobMatch(includes, relPath) {
208			return false
209		}
210		if len(excludes) > 0 && anyGlobMatch(excludes, relPath) {
211			return false
212		}
213		return true
214	}
215	
216	func anyGlobMatch(patterns []string, relPath string) bool {
217		for _, pattern := range patterns {
218			if matchPathGlob(pattern, relPath) {
219				return true
220			}
221		}
222		return false
223	}
224	
225	func matchPathGlob(pattern, name string) bool {
226		pattern = filepath.ToSlash(pattern)
227		name = filepath.ToSlash(name)
228		if matched, _ := filepath.Match(pattern, name); matched {
229			return true
230		}
231		if matched, _ := filepath.Match(pattern, filepath.Base(name)); matched {
232			return true
233		}
234		if !strings.Contains(pattern, "**") {
235			return false
236		}
237		return matchDoubleStar(strings.Split(pattern, "/"), strings.Split(name, "/"))
238	}
239	
240	func matchDoubleStar(patternParts, nameParts []string) bool {
241		if len(patternParts) == 0 {
242			return len(nameParts) == 0
243		}
244		if patternParts[0] == "**" {
245			for i := 0; i <= len(nameParts); i++ {
246				if matchDoubleStar(patternParts[1:], nameParts[i:]) {
247					return true
248				}
249			}
250			return false
251		}
252		if len(nameParts) == 0 {
253			return false
254		}
255		matched, err := filepath.Match(patternParts[0], nameParts[0])
256		if err != nil || !matched {
257			return false
258		}
259		return matchDoubleStar(patternParts[1:], nameParts[1:])
260	}
