525			Title      string   `json:"title,omitempty"`
526			DependsOn  []string `json:"depends_on,omitempty"`
527			Dependents []string `json:"dependents,omitempty"`
528		}
529		nodes := make([]graphNode, 0, len(graph.Documents))
530		for _, doc := range graph.Documents {
531			nodes = append(nodes, graphNode{
532				ID:         doc.ID,
533				Path:       doc.Path,
534				Title:      doc.Title,
535				DependsOn:  doc.DependsOn,
536				Dependents: doc.Dependents,
537			})
538		}
539		sort.Slice(nodes, func(i, j int) bool { return nodes[i].ID < nodes[j].ID })
540		enc := json.NewEncoder(cmd.OutOrStdout())
541		enc.SetIndent("", "  ")
542		return enc.Encode(nodes)
543	}
