545	func printDocGraphText(cmd *cobra.Command, graph *docgraph.Graph) error {
546		if len(graph.Documents) == 0 {
547			fmt.Fprintln(cmd.OutOrStdout(), "No documents with ddx: frontmatter found.")
548			return nil
549		}
550	
551		ids := graph.All()
552		for _, id := range ids {
553			doc := graph.Documents[id]
554			deps := ""
