package docprose

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

// TempValeConfig holds paths to a temporary Vale configuration scoped to one invocation.
type TempValeConfig struct {
	dir     string
	iniPath string
}

// INIPath returns the path to the generated .vale.ini file.
func (t *TempValeConfig) INIPath() string {
	return t.iniPath
}

// StylesPath returns the absolute styles directory written into the generated .vale.ini.
func (t *TempValeConfig) StylesPath() string {
	return filepath.Join(t.dir, "styles")
}

// Cleanup removes all temporary files created for this config.
func (t *TempValeConfig) Cleanup() {
	os.RemoveAll(t.dir)
}

// NewTempValeConfig generates a temporary Vale configuration from DDx settings.
// StylesPath is pointed at the packaged DDx styles via a symlink so no copy is needed.
// Project vocabulary is rendered into Vale accept/reject files under Vocab/Project/.
// The caller must call Cleanup() when done.
func NewTempValeConfig(settings Settings) (*TempValeConfig, error) {
	assetRoot, err := defaultAssetRoot()
	if err != nil {
		return nil, fmt.Errorf("resolve asset root: %w", err)
	}
	packagedDDxStyles := filepath.Join(assetRoot, "styles", "DDx")

	dir, err := os.MkdirTemp("", "ddx-vale-")
	if err != nil {
		return nil, fmt.Errorf("create temp vale dir: %w", err)
	}

	stylesDir := filepath.Join(dir, "styles")
	if err := os.MkdirAll(stylesDir, 0o755); err != nil {
		os.RemoveAll(dir)
		return nil, fmt.Errorf("create styles dir: %w", err)
	}

	// Symlink the packaged DDx style directory so we avoid copying rule files.
	if err := os.Symlink(packagedDDxStyles, filepath.Join(stylesDir, "DDx")); err != nil {
		os.RemoveAll(dir)
		return nil, fmt.Errorf("symlink DDx styles: %w", err)
	}

	vocabName := ""
	if len(settings.Vocabulary.Accept) > 0 || len(settings.Vocabulary.Reject) > 0 {
		vocabName = "Project"
		vocabDir := filepath.Join(stylesDir, "Vocab", vocabName)
		if err := os.MkdirAll(vocabDir, 0o755); err != nil {
			os.RemoveAll(dir)
			return nil, fmt.Errorf("create vocab dir: %w", err)
		}
		if err := writeTextLines(filepath.Join(vocabDir, "accept.txt"), settings.Vocabulary.Accept); err != nil {
			os.RemoveAll(dir)
			return nil, fmt.Errorf("write accept vocabulary: %w", err)
		}
		if err := writeTextLines(filepath.Join(vocabDir, "reject.txt"), settings.Vocabulary.Reject); err != nil {
			os.RemoveAll(dir)
			return nil, fmt.Errorf("write reject vocabulary: %w", err)
		}
	}

	style := settings.Vale.Style
	if style == "" {
		style = "DDx"
	}

	iniPath := filepath.Join(dir, ".vale.ini")
	ini := buildValeINI(stylesDir, style, vocabName)
	if err := os.WriteFile(iniPath, []byte(ini), 0o644); err != nil {
		os.RemoveAll(dir)
		return nil, fmt.Errorf("write .vale.ini: %w", err)
	}

	return &TempValeConfig{dir: dir, iniPath: iniPath}, nil
}

func buildValeINI(stylesPath, style, vocabName string) string {
	var b strings.Builder
	fmt.Fprintf(&b, "StylesPath = %s\n", stylesPath)
	fmt.Fprintf(&b, "MinAlertLevel = suggestion\n")
	if vocabName != "" {
		fmt.Fprintf(&b, "Vocab = %s\n", vocabName)
	}
	fmt.Fprintf(&b, "\n[*.md]\n")
	fmt.Fprintf(&b, "BasedOnStyles = %s\n", style)
	return b.String()
}

func writeTextLines(path string, lines []string) error {
	content := strings.Join(lines, "\n")
	if len(lines) > 0 {
		content += "\n"
	}
	return os.WriteFile(path, []byte(content), 0o644)
}

package docprose

import (
	"os"
	"path/filepath"
	"strings"
	"testing"
)

func TestDocProseValeConfig_NoProjectValeINI(t *testing.T) {
	settings, err := DefaultSettings()
	if err != nil {
		t.Fatal(err)
	}

	cfg, err := NewTempValeConfig(settings)
	if err != nil {
		t.Fatal(err)
	}
	defer cfg.Cleanup()

	data, err := os.ReadFile(cfg.INIPath())
	if err != nil {
		t.Fatalf("read generated .vale.ini: %v", err)
	}
	if len(data) == 0 {
		t.Fatal("generated .vale.ini is empty")
	}
	content := string(data)
	if !strings.Contains(content, "StylesPath") {
		t.Error("generated .vale.ini is missing StylesPath")
	}
	if !strings.Contains(content, "[*.md]") {
		t.Error("generated .vale.ini is missing [*.md] section")
	}
	if !strings.Contains(content, "BasedOnStyles") {
		t.Error("generated .vale.ini is missing BasedOnStyles")
	}
}

func TestDocProseValeConfig_StylesPathUsesPackagedRules(t *testing.T) {
	settings, err := DefaultSettings()
	if err != nil {
		t.Fatal(err)
	}

	cfg, err := NewTempValeConfig(settings)
	if err != nil {
		t.Fatal(err)
	}
	defer cfg.Cleanup()

	// DDx style directory must be accessible via the generated StylesPath.
	ddxStyleDir := filepath.Join(cfg.StylesPath(), "DDx")
	info, err := os.Stat(ddxStyleDir)
	if err != nil {
		t.Fatalf("DDx style dir not accessible at %s: %v", ddxStyleDir, err)
	}
	if !info.IsDir() {
		t.Fatalf("expected %s to be a directory", ddxStyleDir)
	}

	// The INI file must reference the generated StylesPath.
	data, err := os.ReadFile(cfg.INIPath())
	if err != nil {
		t.Fatal(err)
	}
	if !strings.Contains(string(data), cfg.StylesPath()) {
		t.Errorf("generated .vale.ini does not reference expected StylesPath %s\ncontent:\n%s", cfg.StylesPath(), string(data))
	}
}

func TestDocProseValeConfig_ProjectVocabularyRendered(t *testing.T) {
	settings, err := DefaultSettings()
	if err != nil {
		t.Fatal(err)
	}
	settings.Vocabulary.Accept = []string{"DDx", "bead", "Quartz"}
	settings.Vocabulary.Reject = []string{"system"}

	cfg, err := NewTempValeConfig(settings)
	if err != nil {
		t.Fatal(err)
	}
	defer cfg.Cleanup()

	// accept.txt must contain each accept term.
	acceptPath := filepath.Join(cfg.StylesPath(), "Vocab", "Project", "accept.txt")
	data, err := os.ReadFile(acceptPath)
	if err != nil {
		t.Fatalf("read accept.txt: %v", err)
	}
	acceptContent := string(data)
	for _, term := range []string{"DDx", "bead", "Quartz"} {
		if !strings.Contains(acceptContent, term) {
			t.Errorf("accept.txt missing term %q", term)
		}
	}

	// reject.txt must contain each reject term.
	rejectPath := filepath.Join(cfg.StylesPath(), "Vocab", "Project", "reject.txt")
	data, err = os.ReadFile(rejectPath)
	if err != nil {
		t.Fatalf("read reject.txt: %v", err)
	}
	if !strings.Contains(string(data), "system") {
		t.Error("reject.txt missing term 'system'")
	}

	// The INI must declare the Vocab directive.
	iniData, err := os.ReadFile(cfg.INIPath())
	if err != nil {
		t.Fatal(err)
	}
	if !strings.Contains(string(iniData), "Vocab") {
		t.Error("generated .vale.ini does not declare Vocab directive")
	}
}

func TestDocProseValeConfig_CleansTemporaryFiles(t *testing.T) {
	settings, err := DefaultSettings()
	if err != nil {
		t.Fatal(err)
	}
	settings.Vocabulary.Accept = []string{"DDx"}

	cfg, err := NewTempValeConfig(settings)
	if err != nil {
		t.Fatal(err)
	}

	iniPath := cfg.INIPath()
	tempDir := filepath.Dir(iniPath)

	if _, err := os.Stat(iniPath); err != nil {
		t.Fatalf("expected .vale.ini to exist before cleanup: %v", err)
	}

	cfg.Cleanup()

	if _, err := os.Stat(iniPath); !os.IsNotExist(err) {
		t.Errorf("expected .vale.ini to be removed after Cleanup, got: %v", err)
	}
	if _, err := os.Stat(tempDir); !os.IsNotExist(err) {
		t.Errorf("expected temp dir %s to be removed after Cleanup, got: %v", tempDir, err)
	}
}
